        <DropdownMenuSeparator />
        <DropdownMenuItem onSelect={handleLogout} disabled={isPending} className="text-destructive focus:text-destructive">
          <LogOut /> تسجيل الخروج
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
